VALUES
  ('judicial-d35ec6db-moex-00387', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '下列何人非屬國家賠償請求權人？', '["公務員駕駛公務車輛執行職務時不法傷及之路人", "因公平交易委員會違法公開警告行為所侵害之公司", "因台灣電力股份有限公司輸電設施有瑕疵而傾倒壓傷之人", "因市政府管理欠缺之道路坑洞，致人民死亡時，為被害人支出殯葬費之人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00388', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於國家賠償之敘述，下列何者正確？', '["公務員之範圍係狹義公務員，比照公務人員任用法", "國家賠償之方式係完全採金錢賠償", "賠償請求權，自請求權人知有損害時，因1年間不行使而消滅", "公共設施設置或管理欠缺係採無過失責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00389', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'essay', '甲走路不慎碰撞到騎自行車的壯漢 A，A 暴怒，從自行車上拿取打氣筒
衝向甲，並舉手要毆打甲，甲見A身材壯碩又有打氣筒在手，趕忙舉拳
備戰。怎知 A第一擊揮空，且打氣筒順勢甩落於甲腳旁，A低身想撿打
氣筒繼續毆打甲。甲為了保護自己，快一步撿起A的打氣筒，持之揮打
A，A被甲打到手臂流血，甲則趁亂離去。甲之刑責為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "afff917a34a1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00390', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'essay', '甲於餐廳用餐，欲竊取鄰座顧客乙的手機。甲將手伸至隔壁餐桌，取走
置於桌上的手機（實際上為丙所有）。甲至餐廳門口時，丙即發現上情，
並衝上前阻止甲離去，甲為避免丙的追捕，朝其腹部施以數拳。丙因疼痛
難耐而跪倒在地，甲則持該手機逃離現場。甲的刑責應如何論處？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "afff917a34a1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00391', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '對於精神障礙犯罪人施以監護處分之規定，如行為時與裁判時之法律有變更，應如何適用？', '["適用裁判時之法律", "適用行為時之法律", "比較行為時與裁判時之法律，擇最有利於行為人適用之", "比較行為時與裁判時之法律，擇期間最長者適用之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "afff917a34a1", "answer_pdf_sha1": "2fcfec06b8f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00392', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲正在竊取路邊汽車，甲已打開該車車門，正好有警察乙接近，可能發現甲之犯罪行為，甲遂放 棄續行犯罪而離去。有關甲之刑責，下列敘述何者正確？', '["甲成立竊盜罪之障礙未遂", "甲成立竊盜罪之中止未遂", "甲成立竊盜罪之不能未遂", "甲成立竊盜罪之預備犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "afff917a34a1", "answer_pdf_sha1": "2fcfec06b8f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00393', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '關於刑之酌科及加減，下列敘述何者錯誤？', '["對於未發覺之罪自首而受裁判者，減輕其刑", "未滿18歲或滿80歲人犯罪者，不得處死刑或無期徒刑", "刑有加重及減輕者，先加後減", "因刑之加重、減輕，而有不滿1日之時間或不滿1元之額數者，不算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "afff917a34a1", "answer_pdf_sha1": "2fcfec06b8f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00394', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '載運偷渡客的船長甲，見警察上船臨檢，情急之下將船上的偷渡客乙、丙推落海，造成乙、丙溺 斃，事後經法院認定，甲不知道乙、丙不諳水性，雖不願意見到他們死亡，但其死亡對甲而言， 亦未違反其本意。有關甲之主觀犯意，下列何者正確？', '["甲對乙、丙之死亡結果，具直接故意", "甲對乙、丙之死亡結果，具未必故意", "甲對乙、丙之死亡結果，具無認識過失", "甲對乙、丙之死亡結果，具有認識過失"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "afff917a34a1", "answer_pdf_sha1": "2fcfec06b8f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00395', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '小學老師甲因班上9歲女童乙偷東西又頂嘴，因情緒失控而用麥克風丟擲乙之頭部，致乙頭部血 流不止。刑法上應如何評價甲之行為？', '["甲之行為屬業務上正當行為，不罰", "甲之行為屬依法令之行為，不罰", "甲之行為屬過當之依法令行為，成立傷害罪，得減輕其刑", "甲無任何減輕或阻卻事由，成立傷害罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "afff917a34a1", "answer_pdf_sha1": "2fcfec06b8f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00396', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲清晨出門，看到有人未經其同意，擅自將車停放在其家門口，甚為火大，於是拿起地上磚塊， 砸破車窗玻璃。孰知，車主乙在車內燒炭自殺，甲的砸車行為，剛好救了乙一命。甲之行為，屬 於下列何者？', '["誤想防衛", "誤想避難", "偶然防衛", "偶然避難"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "afff917a34a1", "answer_pdf_sha1": "2fcfec06b8f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
